CREATE OR REPLACE FUNCTION fpb_get_coll (as_conno char) RETURNS timestamp(0) AS $body$
DECLARE

li_install timestamp(0);

BEGIN

  select   resignation_approve_date
  into STRICT li_install
  from sc_mem_m_membership_registered
  where membership_no = as_conno;

  return li_install;

end;
